import React, { useState, useEffect } from 'react';
import DisplayStockData from './design';

function View() {
  const [symbol, setSymbol] = useState('');
  const [stockData, setStockData] = useState(null);

  useEffect(() => {
    const fetchData = async () => {
      if (!symbol) {
        return;
      }
      const response = await fetch(`http://127.0.0.1:8000/${symbol}/`);
      const data = await response.json();
      setStockData(data);
    };
    fetchData();
  }, [symbol]);

  useEffect(() => {
    let socket = null;
    if (stockData) {
      socket = new WebSocket('ws://127.0.0.1:8000/ws/stock/' + symbol + '/');
      socket.onmessage = event => {
        const data = JSON.parse(event.data);
        setStockData(data);
      };
    }
    return () => {
      if (socket) {
        socket.close();
      }
    };
  }, [symbol, stockData]);

  const handleSubmit = event => {
    event.preventDefault();
    setSymbol(event.target.symbol.value);
  };

  return (
    <div>
      <form onSubmit={handleSubmit}>
        <input type="text" name="symbol" />
        <button type="submit">Submit</button>
      </form>
      <DisplayStockData stockData={stockData} />
    </div>
  );
}

export default View;
